from agent import *from models.products import *import simplejsondef run(context, session):    session.queue(Request("https://www.macrumors.com/review/", use="curl"), process_category, dict())def process_category(data, context, session):    revs = data.xpath("//div[contains(@class,'block--')]//*[contains(@class,'heading--')]")    for rev in revs:        url = rev.xpath("a/@href").string()        if url:            url = url.split("#")[0]            session.queue(Request(url), process_review, dict(context, url=url))    next_url = data.xpath("//a[@rel='next']/@href").string()    if next_url:        session.queue(Request(next_url), process_category, dict(context))def process_review(data, context, session):    product = Product()    product.url = context['url']    product.ssid = context['url'].split('/')[-2]    product.category = 'Hi-Tech'    title = data.xpath("//h1[contains(@class,'heading--')]//text()")    name = title.string()    if re.search(r"(^Video Review:)|(^Video Reviews:)", name):        product.name = name.split("Review:")[-1].split("Reviews:")[-1].split("the")[0].split("is")[0].split("to")[0].split("and")[0].split("for")[0].split("Your")[0]    elif re.search(r"([^\W+] Video Review:)|([^\W+] Video Reviews:)", name):        product.name = name.split("Review:")[0].split("Reviews:")[0].replace("Video", "")    elif re.search(r"([^\W+] Review)|([^\W+] Reviews)", name):        product.name = name.split("Review")[0].split("Reviews")[0]    elif re.search(r"(^Review:)|(^Reviews:)", name):        product.name = name.split("Review:")[-1].split("Reviews:")[-1].split("the")[0].split("is")[0].split("to")[0].split("and")[0].split("for")[0].split("Your")[0].split("Are")[0].split("$")[0]    else:        product.name = data.xpath("//meta[@name='keywords']/@content").string().split(',')[0]    review = Review()    review.url = product.url    review.title = title.string(multiple=True)    review.ssid = product.ssid    review.type = 'pro'    review.date = data.xpath("//time/@datetime").string().split('T')[0]    author = data.xpath("//div[contains(@class,'titlebar--')]//a[contains(@class,'authorLink--')]").first()    if author:        name = author.xpath("text()").string()        url = author.xpath("@href").string()        if url:            ssid = url.split('/')[-2]            review.authors.append(Person(name=name, ssid=ssid, profile_url=url))        else:            review.authors.append(Person(name=name, ssid=name))    pros = data.xpath("//p[contains(.,'Pros:')]/following-sibling::ul[1]//li")    for pro in pros:        pro = pro.xpath(".//text()").string(multiple=True)        review.add_property(type='pros', value=pro)    cons = data.xpath("//p[contains(.,'Cons:')]/following-sibling::ul[1]//li")    for con in cons:        con = con.xpath(".//text()").string(multiple=True)        review.add_property(type='cons', value=con)    json_body = data.xpath("//script[@type='application/ld+json' and contains(.,'datePublished')]//text()").string()    if json_body:        resp = simplejson.loads(json_body)        grade_overall = resp.get("Review")        if grade_overall:            grade_overall_2 = grade_overall.get("reviewRating")            if grade_overall_2:                grade_overall_3 = grade_overall_2.get("ratingValue")                if grade_overall_3:                    review.grades.append(Grade(type='overall', value=float(grade_overall_3), best=5.0))    excerpt = data.xpath("//div[contains(@class,'ugc--')]//p[not(.//em) and not(contains(.,'Pros:')) and not(contains(.,'Cons:')) and not(./preceding-sibling::h2[contains(.,'How to Buy')])]//text()").string(multiple=True)    if excerpt:        review.add_property(type='excerpt', value=excerpt)        product.reviews.append(review)        session.emit(product)